import 'package:flutter/material.dart';
import '../../owner/owner_store.dart';
import '../../widgets/owner_layout.dart';

class OwnerNewTripScreen extends StatefulWidget{const OwnerNewTripScreen({super.key});@override State<OwnerNewTripScreen> createState()=>_State();}
class _State extends State<OwnerNewTripScreen>{final store=OwnerStore.instance,destination=TextEditingController(),capacity=TextEditingController();String? boatId;DateTime departure=DateTime.now().add(const Duration(days:1)),returnTime=DateTime.now().add(const Duration(days:1,hours:5));@override void dispose(){destination.dispose();capacity.dispose();super.dispose();}Future<void> pick(bool returning)async{final date=await showDatePicker(context:context,firstDate:DateTime.now(),lastDate:DateTime.now().add(const Duration(days:365)),initialDate:returning?returnTime:departure);if(date==null||!mounted)return;final time=await showTimePicker(context:context,initialTime:TimeOfDay.fromDateTime(returning?returnTime:departure));if(time==null)return;setState((){final value=DateTime(date.year,date.month,date.day,time.hour,time.minute);if(returning)returnTime=value;else departure=value;});}void save(){final cap=int.tryParse(capacity.text);if(boatId==null||destination.text.trim().isEmpty||cap==null||cap<=0||returnTime.isBefore(departure)){ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content:Text('Enter a valid vessel, schedule, destination and capacity.')));return;}final boat=store.boat(boatId!)!;if(cap>boat.capacity){ScaffoldMessenger.of(context).showSnackBar(SnackBar(content:Text('Capacity cannot exceed ${boat.capacity}.')));return;}final id='TRIP-${DateTime.now().millisecondsSinceEpoch.toString().substring(7)}';store.addTrip(OwnerTrip(id:id,boatId:boatId!,departure:departure,returnTime:returnTime,destination:destination.text.trim(),passengerCapacity:cap,status:OwnerTripStatus.upcoming,shoreApproval:'Pending',wildlifeApproval:'Pending',qrToken:'WWMS-$id'));Navigator.pop(context);}@override Widget build(BuildContext context){final certified=store.ownedBoats.where((b)=>b.status==CertificationStatus.certified).toList();boatId??=certified.firstOrNull?.id;return OwnerLayout(child:Column(children:[Expanded(child:SingleChildScrollView(padding:const EdgeInsets.all(24),child:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[label('Select A Certified Vessel'),box(DropdownButtonHideUnderline(child:DropdownButton<String>(isExpanded:true,value:boatId,items:certified.map((b)=>DropdownMenuItem(value:b.id,child:Text(b.name))).toList(),onChanged:(v)=>setState(()=>boatId=v)))),label('Departure Date & Time'),dateBox(departure,()=>pick(false)),label('Estimated Return'),dateBox(returnTime,()=>pick(true)),label('Destination'),TextField(controller:destination,decoration:input('Dondra Head')),label('Passenger Capacity'),TextField(controller:capacity,keyboardType:TextInputType.number,decoration:input('30')),if(certified.isEmpty)const Padding(padding:EdgeInsets.only(top:16),child:Text('No certified boats are available.',style:TextStyle(color:Colors.red)))]))),Padding(padding:const EdgeInsets.all(24),child:SizedBox(width:double.infinity,height:56,child:ElevatedButton(style:ElevatedButton.styleFrom(backgroundColor:const Color(0xFF0F172A),foregroundColor:Colors.white),onPressed:certified.isEmpty?null:save,child:const Text('Schedule Trip'))))]));}Widget label(String t)=>Padding(padding:const EdgeInsets.only(top:24,bottom:8),child:Text(t,style:const TextStyle(fontWeight:FontWeight.bold)));Widget box(Widget c)=>Container(padding:const EdgeInsets.symmetric(horizontal:16,vertical:4),decoration:BoxDecoration(border:Border.all(color:Colors.grey.shade200),borderRadius:BorderRadius.circular(12)),child:c);Widget dateBox(DateTime d,VoidCallback tap)=>InkWell(onTap:tap,child:box(Padding(padding:const EdgeInsets.symmetric(vertical:14),child:Row(mainAxisAlignment:MainAxisAlignment.spaceBetween,children:[Text(d.toLocal().toString()),const Icon(Icons.calendar_today_outlined)]))));InputDecoration input(String hint)=>InputDecoration(hintText:hint,border:OutlineInputBorder(borderRadius:BorderRadius.circular(12)));}
